    private val JSON_MEDIA_TYPE = "application/json; charset=utf-8".toMediaType()

    // Secure client for cloud API (HTTPS)
    private val secureClient: OkHttpClient by lazy {
        OkHttpClient.Builder()
            .connectTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .readTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .writeTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .addInterceptor(LoggingInterceptor())
            .addInterceptor(AuthInterceptor())
            .retryOnConnectionFailure(true)
            .build()
    }

    // Insecure client for local IoT devices (HTTP/HTTPS with self-signed certs)
    private val localClient: OkHttpClient by lazy {
        val trustAllCerts = arrayOf<TrustManager>(object : X509TrustManager {
            override fun checkClientTrusted(chain: Array<out X509Certificate>?, authType: String?) {}
            override fun checkServerTrusted(chain: Array<out X509Certificate>?, authType: String?) {}
            override fun getAcceptedIssuers(): Array<X509Certificate> = arrayOf()
        })

        val sslContext = SSLContext.getInstance("TLS")
        sslContext.init(null, trustAllCerts, SecureRandom())

        val hostnameVerifier = HostnameVerifier { _, _ -> true }

        OkHttpClient.Builder()
            .connectTimeout(LOCAL_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .readTimeout(LOCAL_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .writeTimeout(LOCAL_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .sslSocketFactory(sslContext.socketFactory, trustAllCerts[0] as X509TrustManager)
            .hostnameVerifier(hostnameVerifier)
            .addInterceptor(LoggingInterceptor())
            .retryOnConnectionFailure(true)
            .build()
    }

    private var authToken: String? = null

    fun setAuthToken(token: String) {
        authToken = token
    }

    private fun isLocalAddress(url: String): Boolean {
        return url.startsWith("http://192.168.") ||
                url.startsWith("https://192.168.") ||
                url.startsWith("http://10.") ||
                url.startsWith("https://10.") ||
                url.startsWith("http://172.16.") ||
                url.startsWith("https://172.16.") ||
                url.contains(".local")
    }

    private fun getClientForUrl(url: String): OkHttpClient {
        return if (isLocalAddress(url)) localClient else secureClient
    }

    // --- Cloud API methods ---

    fun cloudGet(endpoint: String, callback: ApiCallback) {
        val url = "$CLOUD_BASE_URL$endpoint"
