    // --- Local IoT device methods ---

    fun deviceGet(deviceIp: String, path: String, useHttps: Boolean = false, callback: ApiCallback) {
        val scheme = if (useHttps) "https" else "http"
        val url = "$scheme://$deviceIp$path"
