    fun deviceDelete(deviceIp: String, path: String, useHttps: Boolean = false, callback: ApiCallback) {
        val scheme = if (useHttps) "https" else "http"
        val url = "$scheme://$deviceIp$path"
        delete(url, callback)
    }

    // --- Generic HTTP methods ---

    fun get(url: String, headers: Map<String, String>? = null, callback: ApiCallback) {
        val requestBuilder = Request.Builder().url(url).get()
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        executeRequest(url, requestBuilder.build(), callback)
    }

    fun post(url: String, jsonBody: JSONObject, headers: Map<String, String>? = null, callback: ApiCallback) {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).post(body)
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        executeRequest(url, requestBuilder.build(), callback)
    }

    fun put(url: String, jsonBody: JSONObject, headers: Map<String, String>? = null, callback: ApiCallback) {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).put(body)
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        executeRequest(url, requestBuilder.build(), callback)
    }

    fun delete(url: String, headers: Map<String, String>? = null, callback: ApiCallback) {
        val requestBuilder = Request.Builder().url(url).delete()
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        executeRequest(url, requestBuilder.build(), callback)
    }

    private fun executeRequest(url: String, request: Request, callback: ApiCallback) {
        val client = getClientForUrl(url)

        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                Log.e(TAG, "Request failed: ${request.url}", e)
                callback.onError(ApiError(
                    code = -1,
                    message = e.message ?: "Unknown error",
                    exception = e
                ))
            }

            override fun onResponse(call: Call, response: Response) {
                response.use { resp ->
                    val responseBody = resp.body?.string()
                    if (resp.isSuccessful) {
                        Log.d(TAG, "Request successful: ${request.url} [${resp.code}]")
                        callback.onSuccess(ApiResponse(
                            code = resp.code,
                            body = responseBody,
                            headers = resp.headers
                        ))
                    } else {
                        Log.w(TAG, "Request error: ${request.url} [${resp.code}] $responseBody")
                        callback.onError(ApiError(
                            code = resp.code,
                            message = responseBody ?: "HTTP ${resp.code}",
                            exception = null
                        ))
                    }
                }
            }
        })
    }

    // Synchronous versions for use in coroutines or background threads

    @Throws(IOException::class)
    fun getSync(url: String, headers: Map<String, String>? = null): ApiResponse {
        val requestBuilder = Request.Builder().url(url).get()
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        return executeRequestSync(url, requestBuilder.build())
    }

    @Throws(IOException::class)
    fun postSync(url: String, jsonBody: JSONObject, headers: Map<String, String>? = null): ApiResponse {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).post(body)
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        return executeRequestSync(url, requestBuilder.build())
    }

    @Throws(IOException::class)
    private fun executeRequestSync(url: String, request: Request): ApiResponse {
        val client = getClientForUrl(url)
        val response = client.newCall(request).execute()
        response.use { resp ->
            val responseBody = resp.body?.string()
            if (resp.isSuccessful) {
                return ApiResponse(
                    code = resp.code,
                    body = responseBody,
                    headers = resp.headers
                )
            } else {
                throw IoTApiException(resp.code, responseBody ?: "HTTP ${resp.code}")
            }
        }
    }

    // --- Discovery: ping local devices ---

    fun discoverDevice(ip: String, port: Int = 80, useHttps: Boolean = false, callback: DeviceDiscoveryCallback) {
        val scheme = if (useHttps) "https" else "http"
        val url = "$scheme://$ip:$port/"

        val quickClient = localClient.newBuilder()
            .connectTimeout(3, TimeUnit.SECONDS)
            .readTimeout(3, TimeUnit.SECONDS)
            .build()

        val request = Request.Builder().url(url).head().build()

        quickClient.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                callback.onDeviceNotFound(ip)
            }

            override fun onResponse(call: Call, response: Response) {
                response.close()
                callback.onDeviceFound(DeviceInfo(ip = ip, port = port, isHttps = useHttps))
            }
        })
    }

    fun scanSubnet(
        subnet: String = "192.168.1",
        port: Int = 80,
        useHttps: Boolean = false,
        callback: SubnetScanCallback
    ) {
        var remaining = 254
        val foundDevices = mutableListOf<DeviceInfo>()

        for (i in 1..254) {
            val ip = "$subnet.$i"
            discoverDevice(ip, port, useHttps, object : DeviceDiscoveryCallback {
                override fun onDeviceFound(device: DeviceInfo) {
                    synchronized(foundDevices) {
                        foundDevices.add(device)
                    }
                    checkComplete()
                }

                override fun onDeviceNotFound(ip: String) {
                    checkComplete()
                }

                private fun checkComplete() {
                    synchronized(foundDevices) {
                        remaining--
                        if (remaining == 0) {
                            callback.onScanComplete(foundDevices.toList())
                        }
                    }
                }
            })
        }
    }

    // --- Interceptors ---

    private inner class LoggingInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val request = chain.request()
            val startTime = System.nanoTime()

            Log.d(TAG, "--> ${request.method} ${request.url}")

            val response = chain.proceed(request)

            val duration = (System.nanoTime() - startTime) / 1_000_000
            Log.d(TAG, "<-- ${response.code} ${request.url} (${duration}ms)")

            return response
        }
    }

    private inner class AuthInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val originalRequest = chain.request()

            // Only add auth header for cloud API requests
            if (!isLocalAddress(originalRequest.url.toString()) && authToken != null) {
                val authenticatedRequest = originalRequest.newBuilder()
                    .header("Authorization", "Bearer $authToken")
                    .build()
                return chain.proceed(authenticatedRequest)
            }

            return chain.proceed(originalRequest)
        }
    }

    // --- Data classes and interfaces ---

    data class ApiResponse(
        val code: Int,
        val body: String?,
        val headers: Headers
    ) {
        fun bodyAsJson(): JSONObject? {
            return body?.let {
                try {
                    JSONObject(it)
                } catch (e: Exception) {
                    null
                }
            }
        }
    }

    data class ApiError(
        val code: Int,
        val message: String,
        val exception: Exception?
    )

    data class DeviceInfo(
        val ip: String,
        val port: Int,
        val isHttps: Boolean
    )

    class IoTApiException(val code: Int, message: String) : IOException(message)

    interface ApiCallback {
        fun onSuccess(response: ApiResponse)
        fun onError(error: ApiError)
    }

    interface DeviceDiscoveryCallback {
        fun onDeviceFound(device: DeviceInfo)
        fun onDeviceNotFound(ip: String)
    }

    interface SubnetScanCallback {
        fun onScanComplete(devices: List<DeviceInfo>)
    }
}

