class MainActivity : AppCompatActivity() {

    private val iotClient = IoTHttpClient.getInstance()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Set auth token for cloud API
        iotClient.setAuthToken("your-jwt-token-here")

        // Example: Cloud API GET
        fetchDeviceListFromCloud()

        // Example: Local IoT device control
        controlLocalDevice("192.168.1.100")

        // Example: Scan for devices on local network
        scanForDevices()
    }

    private fun fetchDeviceListFromCloud() {
        iotClient.cloudGet("/v1/devices", object : IoTHttpClient.ApiCallback {
            override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                val json = response.bodyAsJson()
                Log.d("MainActivity", "Cloud devices: $json")
                runOnUiThread {
                    // Update UI with device list
                }
            }

            override fun onError(error: IoTHttpClient.ApiError) {
                Log.e("MainActivity", "Failed to fetch devices: ${error.message}")
                runOnUiThread {
                    // Show error to user
                }
            }
        })
    }

    private fun controlLocalDevice(deviceIp: String) {
        // Turn on a light (HTTP, no TLS)
        val command = JSONObject().apply {
            put("action", "turn_on")
            put("brightness", 100)
        }

        iotClient.devicePost(deviceIp, "/api/light", command, useHttps = false,
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    Log.d("MainActivity", "Device responded: ${response.body}")
                    runOnUiThread {
                        // Update UI
                    }
                }

                override fun onError(error: IoTHttpClient.ApiError) {
                    Log.e("MainActivity", "Device error: ${error.message}")
                    runOnUiThread {
                        // Show error
                    }
                }
            })

        // Get device status
        iotClient.deviceGet(deviceIp, "/api/status", useHttps = false,
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    val status = response.bodyAsJson()
                    Log.d("MainActivity", "Device status: $status")
                }

                override fun onError(error: IoTHttpClient.ApiError) {
                    Log.e("MainActivity", "Status error: ${error.message}")
                }
            })
    }

    private fun scanForDevices() {
        iotClient.scanSubnet("192.168.1", 80, false,
            object : IoTHttpClient.SubnetScanCallback {
                override fun onScanComplete(devices: List<IoTHttpClient.DeviceInfo>) {
                    Log.d("MainActivity", "Found ${devices.size} devices:")
                    devices.forEach { device ->
                        Log.d("MainActivity", "  - ${device.ip}:${device.port}")
                    }
                    runOnUiThread {
                        // Update UI with discovered devices
                    }
                }
            })
    }

    private fun registerDeviceWithCloud(deviceIp: String, deviceName: String) {
        val registrationData = JSONObject().apply {
            put("name", deviceName)
            put("local_ip", deviceIp)
            put("type", "smart_light")
        }

        iotClient.cloudPost("/v1/devices/register", registrationData,
            object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    Log.d("MainActivity", "Device registered: ${response.body}")
                }

                override fun onError(error: IoTHttpClient.ApiError) {
                    Log.e("MainActivity", "Registration failed: ${error.message}")
                }
            })
    }
